/**
 * @summary Get summary report for a reference number
 */
export const getGetSummaryReportUrl = (refNo: string) => {
  return `/api/reports/${refNo}`;
};

export const getSummaryReport = async (
  refNo: string,
  options?: RequestInit,
): Promise<SummaryReport> => {
  return customFetch<SummaryReport>(getGetSummaryReportUrl(refNo), {
    ...options,
    method: "GET",
  });
};

export const getGetSummaryReportQueryKey = (refNo: string) => {
  return [`/api/reports/${refNo}`] as const;
};

export const getGetSummaryReportQueryOptions = <
  TData = Awaited<ReturnType<typeof getSummaryReport>>,
  TError = ErrorType<unknown>,
>(
  refNo: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getSummaryReport>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetSummaryReportQueryKey(refNo);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getSummaryReport>>
  > = ({ signal }) => getSummaryReport(refNo, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!refNo,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getSummaryReport>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetSummaryReportQueryResult = NonNullable<
  Awaited<ReturnType<typeof getSummaryReport>>
>;
export type GetSummaryReportQueryError = ErrorType<unknown>;

/**
 * @summary Get summary report for a reference number
 */

export function useGetSummaryReport<
  TData = Awaited<ReturnType<typeof getSummaryReport>>,
  TError = ErrorType<unknown>,
>(
  refNo: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getSummaryReport>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetSummaryReportQueryOptions(refNo, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

